{
  "title": "System Job Log Check and Morning Brief Generation",
  "job": "Generate a morning brief for THE MACHINE COMMAND. Check the logs/ directory for recent job activity. Read config/HEARTBEAT.md for system status. Summarize: what jobs ran recently, what's configured and running, any errors in job logs. Format as punchy bullets — Ty has ADD, bullets not paragraphs. Save the brief to logs/briefs/$(date +%d%m%y)_BRIEF_1.md and print the summary."
}

{
  "title": "Morning System Status Brief Generator",
  "job": "Generate a morning brief for THE MACHINE COMMAND. Check the logs/ directory for recent job activity. Read config/HEARTBEAT.md for system status. Summarize: what jobs ran recently, what's configured and running, any errors in job logs. Format as punchy bullets — Ty has ADD, bullets not paragraphs. Save the brief to logs/briefs/$(date +%d%m%y)_BRIEF_1.md and print the summary."
}

[
  {
    "name": "on-github-event",
    "watch_path": "/github/webhook",
    "actions": [
      { "type": "command", "command": "echo 'github webhook fired'" }
    ],
    "enabled": false
  },
  {
    "name": "on-webhook-log",
    "watch_path": "/webhook",
    "actions": [
      { "type": "command", "command": "echo 'webhook received: {{body}}'" }
    ],
    "enabled": false
  },
  {
    "name": "review-github-event",
    "watch_path": "/github/webhook",
    "actions": [
      { "type": "agent", "job": "A GitHub event occurred. Review the payload and summarize what happened:\n{{body}}" }
    ],
    "enabled": false
  },
  {
    "name": "react-to-webhook",
    "watch_path": "/webhook",
    "actions": [
      { "type": "agent", "job": "A webhook was received. Analyze the payload and decide if any action is needed:\n{{body}}" }
    ],
    "enabled": false
  },
  {
    "name": "forward-github",
    "watch_path": "/github/webhook",
    "actions": [
      { "type": "webhook", "url": "https://example.com/hook", "method": "POST", "vars": { "source": "github" } }
    ],
    "enabled": false
  },
  {
    "name": "forward-webhook",
    "watch_path": "/webhook",
    "actions": [
      { "type": "webhook", "url": "https://example.com/hook", "method": "POST", "vars": { "source": "webhook" } }
    ],
    "enabled": false
  },
  {
    "name": "review-with-openai",
    "watch_path": "/github/webhook",
    "actions": [
      { "type": "agent", "job": "Review the GitHub event and summarize what happened:\n{{body}}", "llm_provider": "openai", "llm_model": "gpt-4o" }
    ],
    "enabled": false
  }
]
